content.text:
/* ── Dark, clean theme ── */

/* System font stack, reset body */
body {
  margin: 0;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen,
    Ubuntu, Cantarell, "Fira Sans", "Droid Sans", "Helvetica Neue", Arial,
    sans-serif;
  font-size: 14px;
  color: #e6e6e6;
  background: #1e1e1e;
}

/* Subtle accent link – used sparingly */
a {
  color: #6aa6ff;
  text-decoration: none;
}
a:hover {
  text-decoration: underline;
}

/* ── Trigger button (toggle file browser) ── */
.trigger {
  padding: 8px 16px;
  cursor: pointer;
  background: #3a3d41;
  border: none;
  color: inherit;
  border-radius: 4px;
  font-size: 14px;
}
.trigger:hover {
  background: #45494d;
}

/* ── Native <dialog> styling ── */
.browser-dialog {
  background: #252526;
  color: #e6e6e6;
  border: 1px solid #3c3c3c;
  border-radius: 8px;
  max-width: 960px;
  width: 90vw;
  padding: 16px;
  /* Remove default UA margin/padding */
  margin: auto;
  box-sizing: border-box;
}
.browser-dialog::backdrop {
  background: rgba(0, 0, 0, 0.6);
}

/* ── Header row ── */
.dialog-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 12px;
}
.dialog-header h2 {
  margin: 0;
  font-size: 16px;
  font-weight: 600;
}
.dialog-header .close-btn {
  background: none;
  border: none;
  color: #9a9a9a;
  cursor: pointer;
  font-size: 20px;
  line-height: 1;
  padding: 4px 8px;
  border-radius: 4px;
}
.dialog-header .close-btn:hover {
  color: #e6e6e6;
  background: #2d2d30;
}

/* ── Toolbar ── */
.toolbar {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  align-items: center;
  margin-bottom: 12px;
}

/* Breadcrumb */
.breadcrumb {
  display: flex;
  align-items: center;
  gap: 4px;
  flex-wrap: wrap;
}
.breadcrumb a {
  color: #9a9a9a;
  font-size: 13px;
}
.breadcrumb a:hover {
  color: #e6e6e6;
  text-decoration: none;
}
.breadcrumb .separator {
  color: #3c3c3c;
  margin: 0 2px;
}

/* Search input */
.toolbar input[type="search"],
.toolbar input[type="text"] {
  background: #333337;
  color: #e6e6e6;
  border: 1px solid #3c3c3c;
  border-radius: 4px;
  padding: 6px 10px;
  font-size: 13px;
  outline: none;
  box-sizing: border-box;
}
.toolbar input[type="search"]::placeholder,
.toolbar input[type="text"]::placeholder {
  color: #9a9a9a;
}
.toolbar input[type="search"]:focus,
.toolbar input[type="text"]:focus {
  border-color: #6aa6ff;
}

/* Upload label styled as button */
.toolbar label.upload-btn {
  display: inline-flex;
  align-items: center;
  padding: 6px 12px;
  cursor: pointer;
  background: #3a3d41;
  border: none;
  color: inherit;
  border-radius: 4px;
  font-size: 13px;
  white-space: nowrap;
}
.toolbar label.upload-btn:hover {
  background: #45494d;
}
.toolbar label.upload-btn input[type="file"] {
  display: none;
}

/* ── Results container (scrollable) ── */
.results-container {
  max-height: 60vh;
  overflow: auto;
  border: 1px solid #3c3c3c;
  border-radius: 4px;
}

/* ── Table ── */
.results-table {
  width: 100%;
  border-collapse: collapse;
  table-layout: auto;
}
.results-table th,
.results-table td {
  padding: 6px 8px;
  border-bottom: 1px solid #3c3c3c;
  text-align: left;
  white-space: nowrap;
}
.results-table th {
  color: #9a9a9a;
  font-weight: 500;
  position: sticky;
  top: 0;
  background: #252526;
  z-index: 1;
}
.results-table tbody tr:hover {
  background: #2d2d30;
}

/* Folder rows – slightly heavier weight */
.results-table .folder-row td {
  font-weight: 600;
}

/* ── Small action buttons ── */
.btn {
  display: inline-flex;
  align-items: center;
  padding: 4px 10px;
  cursor: pointer;
  background: #3a3d41;
  border: none;
  color: inherit;
  border-radius: 4px;
  font-size: 12px;
  line-height: 1.4;
  white-space: nowrap;
}
.btn:hover {
  background: #45494d;
}
.btn:disabled {
  opacity: 0.5;
  cursor: default;
}
.btn:disabled:hover {
  background: #3a3d41;
}

/* ── Status footer ── */
.status {
  margin-top: 8px;
  color: #9a9a9a;
  font-size: 12px;
  display: flex;
  justify-content: space-between;
  align-items: center;
}
